import{_ as t,o,c as a,a2 as r}from"./chunks/framework.D14Z5eOz.js";const p=JSON.parse('{"title":"What you can achieve with sdd","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/what-you-can-achieve.md","filePath":"concepts/what-you-can-achieve.md","lastUpdated":1784865624000}'),d={name:"concepts/what-you-can-achieve.md"};function s(c,e,i,n,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="what-you-can-achieve-with-sdd" tabindex="-1">What you can achieve with sdd <a class="header-anchor" href="#what-you-can-achieve-with-sdd" aria-label="Permalink to &quot;What you can achieve with sdd&quot;">​</a></h1><h2 id="for-any-team-size" tabindex="-1">For any team size <a class="header-anchor" href="#for-any-team-size" aria-label="Permalink to &quot;For any team size&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Goal</th><th>How sdd helps</th></tr></thead><tbody><tr><td><strong>Ship with a paper trail</strong></td><td>Each PR/task gets a change pack: intent, design, tasks, verify notes</td></tr><tr><td><strong>Use AI without losing decisions</strong></td><td>Agents read live context + protocol; specs stay in git</td></tr><tr><td><strong>Match ceremony to risk</strong></td><td>Hotfix in 3 stages; full feature or enterprise ARB when needed</td></tr><tr><td><strong>Stay local</strong></td><td>No cloud account for the process tool itself</td></tr><tr><td><strong>Standardize process in the repo</strong></td><td>Workflows are YAML your org can fork and version</td></tr></tbody></table><h2 id="concrete-outcomes" tabindex="-1">Concrete outcomes <a class="header-anchor" href="#concrete-outcomes" aria-label="Permalink to &quot;Concrete outcomes&quot;">​</a></h2><ul><li>Start a change: <code>sdd new &quot;…&quot;</code> → recommended or chosen workflow</li><li>Move through stages: fill markdown → <code>sdd next</code></li><li>Improve specs anytime: <code>sdd refine</code> (stage-scoped; constitution read-only)</li><li>Give agents focused code: <code>sdd context</code> (AST slices for TS/JS)</li><li>Verify on the laptop: <code>sdd verify</code></li><li>Close work: <code>sdd complete</code> (pack stays under <code>changes/</code> by default)</li><li>Switch concurrent work: <code>sdd checkout &lt;id&gt;</code></li><li>Check setup: <code>sdd doctor</code></li></ul><h2 id="solo-vs-product-team-vs-enterprise" tabindex="-1">Solo vs product team vs enterprise <a class="header-anchor" href="#solo-vs-product-team-vs-enterprise" aria-label="Permalink to &quot;Solo vs product team vs enterprise&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Context</th><th>Typical use</th></tr></thead><tbody><tr><td><strong>Solo / small team</strong></td><td><code>hotfix</code> or <code>feature</code>, optional agent launch, light memory</td></tr><tr><td><strong>Product team</strong></td><td>Shared <code>feature</code> / <code>patch</code> packs, constitution in <code>memory/</code>, PR review of packs</td></tr><tr><td><strong>Enterprise</strong></td><td><code>enterprise-feature</code> (ARB, LLD, DB, research, stories), hard gates, skip flags for N/A stages</td></tr></tbody></table><p>Same CLI — different <strong>workflow packs</strong> and policy in YAML.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../guides/simple-feature">Simple feature</a></li><li><a href="./../guides/enterprise">Enterprise path</a></li><li><a href="./../reference/workflows">Built-in workflows</a></li></ul>',10)])])}const f=t(d,[["render",s]]);export{p as __pageData,f as default};
